//---------------------------------------------------------
// 저장 (오더별매입현황) / f_save()
//---------------------------------------------------------
scwin.btn_saveSell_onClick = async function (e) {
  if (await $c.win.confirm($p, MSG_CM_CRM_001)) {
    //저장하시겠습니까?

    if (ds_ord.getModifiedIndex().length > 0) {
      let checkedCnt = 0;
      for (let i = 0; i < ds_ord.getTotalRow(); i++) {
        if (ds_ord.getCellData(i, "chk") == "T") {
          checkedCnt++;
          break;
        }
      }
      for (i = 0; i < ds_ord.getTotalRow(); i++) {
        if (ds_ord.getCellData(i, "chk") == "T" && ds_ord.getCellData(i, "vehclNo") == "") {
          $c.win.alert($p, i + 1 + "번째 데이타의 차량번호를 입력하십시오.");
          return;
        }
        if (ds_ord.getCellData(i, "chk") == "T" && ds_ord.getCellData(i, "pchsClntNo") == "") {
          $c.win.alert($p, i + 1 + "번째 데이타의 매입거래처를 입력하십시오.");
          return;
        }
        if (ds_ord.getCellData(i, "chk") == "T" && ds_ord.getCellData(i, "copCoClntNo") == "") {
          $c.win.alert($p, i + 1 + "번째 데이타의 협력업체를 입력하십시오.");
          return;
        }
      }
      if (checkedCnt == 0) {
        $c.win.alert($p, "체크된 데이터가 없습니다.");
        return false;
      }
      if ($c.gus.cfValidate($p, [gr_orderEachUnityPurchaseList])) {
        $c.sbm.execute($p, sbm_savePchsInfo);
      }
    } else {
      $c.win.alert($p, $c.data.getMessage($p, MSG_CM_ERR_001, "통합매입일괄수정")); //@은(는) 변경된 사항이 없습니다.
    }
  }
};

