//---------------------------------------------------------
//validation 체크 (통합매입 수정및 신규 정보)
//---------------------------------------------------------
scwin.f_validatePchsInfo = function () {
  let validExp = "";
  for (i = 0; i < ds_pchsInfo.getRowCount(); i++) {
    if (ds_pchsInfo.getRowStatus(i) == "C" || ds_pchsInfo.getRowStatus(i) == "U") {
      //행추가 및 수정 상태인 경우 체크
      if ($c.gus.cfIsNull($p, ds_pchsInfo.getCellData(i, "selpchItemNm"))) {
        $c.win.alert($p, $c.data.getMessage($p, MSG_CM_ERR_002, "매입항목 ")); //@은(는) 필수 입력 항목입니다
        return false;
      }
      if ($c.gus.cfIsNull($p, ds_pchsInfo.getCellData(i, "pchsGoodsPatternCd"))) {
        $c.win.alert($p, $c.data.getMessage($p, MSG_CM_ERR_002, "매입품목유형 ")); //@은(는) 필수 입력 항목입니다
        return false;
      }
      if ($c.gus.cfIsNull($p, ds_pchsInfo.getCellData(i, "unitCd"))) {
        $c.win.alert($p, $c.data.getMessage($p, MSG_CM_ERR_002, "단위 ")); //@은(는) 필수 입력 항목입니다
        return false;
      }
      if ($c.gus.cfIsNull($p, ds_pchsInfo.getCellData(i, "vol"))) {
        $c.win.alert($p, $c.data.getMessage($p, MSG_CM_ERR_002, "수량 ")); //@은(는) 필수 입력 항목입니다
        return false;
      }
      if ($c.gus.cfIsNull($p, ds_pchsInfo.getCellData(i, "pchsUpr"))) {
        $c.win.alert($p, $c.data.getMessage($p, MSG_CM_ERR_002, "단가 ")); //@은(는) 필수 입력 항목입니다
        return false;
      }
      if ($c.gus.cfIsNull($p, ds_pchsInfo.getCellData(i, "pchsAmt"))) {
        $c.win.alert($p, $c.data.getMessage($p, MSG_CM_ERR_002, "금액 ")); //@은(는) 필수 입력 항목입니다
        return false;
      }
      if ($c.gus.cfIsNull($p, ds_pchsInfo.getCellData(i, "vat"))) {
        $c.win.alert($p, $c.data.getMessage($p, MSG_CM_ERR_002, "부가세 ")); //@은(는) 필수 입력 항목입니다
        return false;
      }
      if ($c.gus.cfIsNull($p, ds_pchsInfo.getCellData(i, "pchsClntNm"))) {
        $c.win.alert($p, $c.data.getMessage($p, MSG_CM_ERR_002, "매입거래처 ")); //@은(는) 필수 입력 항목입니다
        return false;
      }
      if ($c.gus.cfIsNull($p, ds_pchsInfo.getCellData(i, "copCoClntNm"))) {
        $c.win.alert($p, $c.data.getMessage($p, MSG_CM_ERR_002, "협력업체 ")); //@은(는) 필수 입력 항목입니다
        return false;
      }
      if ($c.gus.cfIsNull($p, ds_pchsInfo.getCellData(i, "rsltsStdDt"))) {
        $c.win.alert($p, $c.data.getMessage($p, MSG_CM_ERR_002, "실적일 ")); //@은(는) 필수 입력 항목입니다
        return false;
      }
      if ($c.gus.cfIsNull($p, ds_pchsInfo.getCellData(i, "bizDomNm"))) {
        $c.win.alert($p, $c.data.getMessage($p, MSG_CM_ERR_002, "사업영역 ")); //@은(는) 필수 입력 항목입니다
        return false;
      }
      if ($c.gus.cfIsNull($p, ds_pchsInfo.getCellData(i, "pchsDeptNm"))) {
        $c.win.alert($p, $c.data.getMessage($p, MSG_CM_ERR_002, "부서 ")); //@은(는) 필수 입력 항목입니다
        return false;
      }
      ds_pchsInfo.setCellData(i, "pchsMainMainPattern", acb_pchsMainMainPattern.getValue());
      ds_pchsInfo.setCellData(i, "pchsMainMainRsn", "");
    }
  }
  return true;
};

