  ds_pchsInfo.setCellData(insertRow, "pchsGoodsPatternNm", ds_pchsInfo.getCellData(row, "pchsGoodsPatternNm"));
  ds_pchsInfo.setCellData(insertRow, "pchsCommNo", ds_pchsInfo.getCellData(row, "pchsCommNo"));
  ds_pchsInfo.setCellData(insertRow, "commCd", ds_pchsInfo.getCellData(row, "commCd"));
  ds_pchsInfo.setCellData(insertRow, "pchsCommNm", ds_pchsInfo.getCellData(row, "pchsCommNm"));
  ds_pchsInfo.setCellData(insertRow, "unitCd", ds_pchsInfo.getCellData(row, "unitCd"));
  ds_pchsInfo.setCellData(insertRow, "vol", Number(ds_pchsInfo.getCellData(row, "vol")));
  ds_pchsInfo.setCellData(insertRow, "pchsUpr", Number(ds_pchsInfo.getCellData(row, "pchsUpr")));
  ds_pchsInfo.setCellData(insertRow, "pchsAmt", Number(ds_pchsInfo.getCellData(row, "pchsAmt")));
