scwin.f_setGridColumnPropEdit = function (gr_pchsInfo, arrColumn, value) {
  for (var i in arrColumn) {
    if (arrColumn[i] != null) {
      if (value == "None") {
        gr_pchsInfo.removeHeaderClass(arrColumn[i], "txt-red");
        gr_pchsInfo.setHeaderColor(arrColumn[i], "black");
      } else {
        // gr_pchsInfo.removeHeaderClass(arrColumn[i], "txt-red");
        gr_pchsInfo.setHeaderClass(arrColumn[i], "txt-red");
      }
    }
  }
};

//-------------------------------------------------------------------------
// 행삭제 
//-------------------------------------------------------------------------
scwin.f_deleteRow = function () {
  if (ds_pchsInfo.getTotalRow() == 0) {
    return;
  }
  let row = ds_pchsInfo.getRowPosition();
  if (ds_pchsInfo.getCellData(row, "dcsnClsCd") == "1") {
    if (ds_pchsInfo.getRowStatus(row) == "C") {
      ds_pchsInfo.removeRow(row);
      gr_pchsInfo.setFocusedCell(ds_pchsInfo.getRowCount() - 1, 0);
    } else {
      ds_pchsInfo.deleteRow(row);
      gr_pchsInfo.setFocusedCell(row, 0);
    }
  }

  // ds_pchsInfo.removeRow(ds_pchsInfo.getRowPosition());

  spa_totalRow2.setValue(ds_pchsInfo.getTotalRow());
};

